script.text:
      /* <flatten type="Javascript"> */
function active$Form$(f) {f.add_onResponseComplete(on$Form$ResponseComplete);}
function close$Form$(f) {try {f.remove_onResponseComplete(on$Form$ResponseComplete);} catch (ex) {}}
function onChangeUserName(o) {o.parentForm.request('GetUserID', 'UserID', ['name']);}
function on$Form$ResponseComplete(sender, e) {
  var f = e.object, context = e.type.Context, result = e.type.Result;
  switch (context) {
    case 'UserID':
      f.getItem('user_id').value = result[0].Value;
      f.getItem('user_yn').value = result[1].Value;
      break;
    default:
      break;
  }
}
/* </flatten> */
